import { forwardRef, useRef } from 'react';
import { useTooltip, type TooltipProp } from '../../hooks/useTooltip';

export interface O9ButtonProps extends Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, 'type' | 'disabled'> {
  variant?: 'primary' | 'secondary' | 'tertiary' | 'outline' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  type?: 'button' | 'submit' | 'reset';
  label: string;
  icon?: string;
  isDisabled?: boolean;
  isSelected?: boolean;
  isFullWidth?: boolean;
  isLoading?: boolean;
  tooltip?: TooltipProp;
}

const O9Button = forwardRef<HTMLButtonElement, O9ButtonProps>(
  function O9Button(
    {
      variant = 'primary',
      size = 'md',
      type = 'button',
      label,
      icon,
      isDisabled = false,
      isSelected,
      isFullWidth = false,
      isLoading = false,
      tooltip,
      className,
      onClick,
      onKeyDown,
      ...rest
    },
    ref
  ) {
    const internalRef = useRef<HTMLButtonElement | null>(null);

    useTooltip({ triggerRef: internalRef, tooltip });
    const classes = [
      'o9ds-btn',
      `o9ds-btn--${variant}`,
      `o9ds-btn--${size}`,
      isFullWidth ? 'o9ds-btn--full-width' : '',
      isLoading ? 'loading' : '',
      isSelected === true ? 'active' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const blocked = isDisabled || isLoading;

    const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
      if (blocked) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onClick?.(e);
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLButtonElement>) => {
      if (blocked && (e.key === 'Enter' || e.key === ' ')) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onKeyDown?.(e);
    };

    const ariaPressedProp = isSelected !== undefined ? { 'aria-pressed': isSelected } : {};

    const mergeRefs = (node: HTMLButtonElement | null) => {
      internalRef.current = node;
      if (typeof ref === 'function') ref(node);
      else if (ref) ref.current = node;
    };

    return (
      <button
        ref={mergeRefs}
        type={type}
        className={classes}
        disabled={isDisabled}
        aria-busy={isLoading ? true : undefined}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        {...ariaPressedProp}
        {...rest}
      >
        {icon && (
          <span
            className={`o9ds-btn__ico o9con o9con-${icon}`}
            aria-hidden="true"
          />
        )}
        <span className="o9ds-btn__lbl">{label}</span>
      </button>
    );
  }
);

export default O9Button;
